import React from 'react';
import { ArrowRight } from 'lucide-react';

const Layanan = () => {
  return (
    <div className="min-h-screen bg-white flex items-center justify-center p-6 sm:p-8 lg:p-12">
      <div className="max-w-7xl w-full grid grid-cols-1 lg:grid-cols-2 gap-12 lg:gap-20 items-center">

        {/* Kolom Kiri: Teks dan Tombol */}
        <div className="flex flex-col items-start">

          {/* Badge Label */}
          <div className="bg-[#FCECD9] text-[#B37031] text-[10px] sm:text-xs font-bold px-4 py-1.5 rounded-full uppercase tracking-widest mb-6">
            Kekuatan & Presisi
          </div>

          {/* Heading */}
          <h1 className="text-5xl lg:text-[64px] font-extrabold text-[#1A1A1A] leading-[1.1] tracking-tight mb-6">
            Layanan Pengiriman <br />
            <span className="text-[#FBC108]">Barang Kami</span>
          </h1>

          {/* Deskripsi */}
          <p className="text-gray-600 text-lg sm:text-xl leading-relaxed mb-10 max-w-lg">
            Kami menyediakan beberapa pilihan kendaraan untuk membantu pengiriman barang Anda. Silakan pilih sesuai dengan kebutuhan ukuran dan jumlah barang.
          </p>

          {/* Tombol Aksi */}
          <div className="flex flex-wrap items-center gap-4 sm:gap-6">
            <button className="bg-[#FBC108] hover:bg-[#E5AF06] text-white font-bold py-3.5 px-8 rounded-md flex items-center gap-2 transition-colors duration-300">
              Mulai Kirim Sekarang <ArrowRight className="w-5 h-5" />
            </button>
            <button className="text-[#1A1A1A] font-bold py-3.5 px-4 hover:text-gray-600 transition-colors duration-300">
              Pelajari Layanan
            </button>
          </div>

        </div>

        {/* Kolom Kanan: Gambar dengan Overlay */}
        <div className="relative w-full aspect-[4/3] rounded-2xl overflow-hidden shadow-lg group">

          {/* Gambar - Menggunakan gambar dummy kendaraan (kamu bisa ganti src ini dengan gambar aslimu) */}
          <img
            src="https://images.unsplash.com/photo-1519003722824-194d4455a60c?q=80&w=1000&auto=format&fit=crop"
            alt="Armada Kendaraan Pengiriman"
            className="w-full h-full object-cover group-hover:scale-105 transition-transform duration-700"
          />

          {/* Gradient Overlay Gelap di Bagian Bawah */}
          <div className="absolute inset-0 bg-gradient-to-t from-black/80 via-black/20 to-transparent"></div>

          {/* Teks Overlay (Statistik) */}
          <div className="absolute bottom-0 left-0 p-8">
            <h3 className="text-white text-5xl font-bold mb-2">
              99.8%
            </h3>
            <p className="text-gray-200 text-sm font-medium tracking-[0.2em] uppercase">
              Tingkat Ketepatan Waktu
            </p>
          </div>

        </div>

      </div>
    </div>
  );
};

export default Layanan;
